#include <bits/stdc++.h>
using namespace std;

const int N=24;

int op[8][7]={
    {0,2,6,11,15,20,22},
    {1,3,8,12,17,21,23},
    {10,9,8,7,6,5,4},
    {19,18,17,16,15,14,13},
    {23,21,17,12,8,3,1},
    {22,20,15,11,6,2,0},
    {13,14,15,16,17,18,19},
    {4,5,6,7,8,9,10},
};

int opposite[8]={5,4,7,6,1,0,3,2};
int center[8]={6,7,8,11,12,15,16,17};

int q[N];
int path[102];

int f(){
    int sum[4]={0,0,0,0};
    for(int i=0;i<8;i++)
        sum[q[center[i]]]++;
    int s=0;
    for(int i=1;i<4;i++)
        s=max(s,sum[i]);
    return 8-s;
}

void operate(int x){
    int t=q[op[x][0]];
    for(int i=0;i<6;i++)
        q[op[x][i]]=q[op[x][i+1]];
    q[op[x][6]]=t;
}

bool dfs(int dep,int md,int last){
    if(dep+f()>md)
        return 0;
    if(!f())
        return 1;
    for(int i=0;i<8;i++)
        if(last!=opposite[i]){
            operate(i);
            path[dep]=i;
            if(dfs(dep+1,md,i))return 1;
            operate(opposite[i]);
        }
    return 0;
}

int main(){
    while(1){
        scanf("%d",&q[0]);
        if(!q[0])
            break;
        for(int i=1;i<N;i++)
            scanf("%d",&q[i]);
        int dep=0;
        while(!dfs(0,dep,-1))
            dep++;
        if(!dep)
            printf("No moves needed");
        else
            for(int i=0;i<dep;i++)
                printf("%c",path[i]+'A');
        printf("\n%d\n",q[6]);
    }
    return 0;
}
